import { randomUUID } from "node:crypto";
import { RecordId } from "surrealdb";
import { extractStructuredGraph } from "../extraction/extract-graph";
import { persistExtractionOutput } from "../extraction/persist-extraction";
import { loadWorkspaceGraphContext } from "../extraction/context-loaders";
import { loadWorkspaceProjects } from "../workspace/workspace-scope";
import { findWorkspaceIdentityByName } from "../extraction/identity-resolution";
import { createEmbedding } from "../extraction/embedding-writeback";
import { createObservation } from "../observation/queries";
import { elapsedMs } from "../http/observability";
import type { SourceRecord } from "../extraction/types";
import { updateTaskStatus } from "../mcp/mcp-queries";
import { extractReferencedTaskIds } from "./commit-task-refs";
import { determineTaskStatusUpdates } from "./task-status-from-push";
import { classifyDecisionLinks } from "./types";
import type { CommitInput, ProcessCommitResult, ProcessWebhookInput, ProcessWebhookResult, TaskStatusUpdateResult } from "./types";
import { log } from "../telemetry/logger";

export async function processGitCommits(input: ProcessWebhookInput): Promise<ProcessWebhookResult> {
  const startedAt = performance.now();
  const workspaceId = input.workspaceRecord.id as string;

  log.info("webhook.commits.started", "Processing commits", {
    workspaceId,
    repository: input.event.repository.full_name,
    commitCount: input.event.commits.length,
  });

  const projects = await loadWorkspaceProjects(input.surreal, input.workspaceRecord);
  const projectNames = projects.map((p) => p.name);

  const [workspaceRows] = await input.surreal
    .query<[Array<{ name: string }>]>("SELECT name FROM $workspace LIMIT 1;", {
      workspace: input.workspaceRecord,
    })
    .collect<[Array<{ name: string }>]>();
  const workspaceName = workspaceRows[0]?.name;

  const isDefaultBranch = input.event.ref === `refs/heads/${input.event.repository.default_branch}`;

  const result: ProcessWebhookResult = {
    commitsProcessed: 0,
    commitsSkipped: 0,
    totalEntities: 0,
    totalRelationships: 0,
    autoLinkedDecisions: [],
    observationsCreated: [],
    taskStatusUpdates: [],
  };

  for (const rawCommit of input.event.commits) {
    const commit: CommitInput = {
      sha: rawCommit.id,
      message: rawCommit.message,
      authoredAt: rawCommit.timestamp,
      authorName: rawCommit.author.name,
      authorEmail: rawCommit.author.email,
      authorUsername: rawCommit.author.username,
      url: rawCommit.url,
      repository: input.event.repository.full_name,
    };

    try {
      const commitResult = await processCommit({
        surreal: input.surreal,
        extractionModel: input.extractionModel,
        embeddingModel: input.embeddingModel,
        embeddingDimension: input.embeddingDimension,
        extractionStoreThreshold: input.extractionStoreThreshold,
        extractionModelId: input.extractionModelId,
        workspaceRecord: input.workspaceRecord,
        commit,
        workspaceName,
        projectNames,
        autoLinkThreshold: input.autoLinkThreshold,
        isDefaultBranch,
        now: new Date(),
      });

      result.commitsProcessed += 1;
      result.totalEntities += commitResult.entities.length;
      result.totalRelationships += commitResult.relationships.length;
      result.autoLinkedDecisions.push(...commitResult.autoLinkedDecisions);
      result.observationsCreated.push(...commitResult.observationsCreated);
      result.taskStatusUpdates.push(...commitResult.taskStatusUpdates);
    } catch (error) {
      log.error("webhook.commit.failed", "Failed to process commit", error, {
        workspaceId,
        sha: commit.sha,
      });
      result.commitsSkipped += 1;
    }
  }

  log.info("webhook.commits.completed", "Finished processing commits", {
    workspaceId,
    ...result,
    durationMs: elapsedMs(startedAt),
  });

  return result;
}

async function processCommit(input: {
  surreal: typeof import("surrealdb").Surreal.prototype;
  extractionModel: unknown;
  embeddingModel: unknown;
  embeddingDimension: number;
  extractionStoreThreshold: number;
  extractionModelId: string;
  workspaceRecord: RecordId<"workspace", string>;
  commit: CommitInput;
  workspaceName?: string;
  projectNames?: string[];
  autoLinkThreshold: number;
  isDefaultBranch: boolean;
  now: Date;
}): Promise<ProcessCommitResult> {
  const commitRecordId = randomUUID();
  const commitRecord = new RecordId("git_commit", commitRecordId);

  // Resolve author identity
  const authorRecord = await findWorkspaceIdentityByName({
    surreal: input.surreal,
    workspaceRecord: input.workspaceRecord,
    identityName: input.commit.authorName,
  });

  // Create embedding for commit message
  const embedding = await createEmbedding(
    input.embeddingModel,
    input.embeddingDimension,
    input.commit.message,
  );

  // Persist git_commit record
  await input.surreal.create(commitRecord).content({
    sha: input.commit.sha,
    repository: input.commit.repository,
    message: input.commit.message,
    authored_at: new Date(input.commit.authoredAt),
    ...(authorRecord ? { author: authorRecord } : {}),
    author_name: input.commit.authorName,
    url: input.commit.url,
    workspace: input.workspaceRecord,
    ...(embedding ? { embedding } : {}),
    created_at: input.now,
  });

  log.info("webhook.commit.created", "Created git_commit record", {
    sha: input.commit.sha,
    commitRecordId,
  });

  const referencedTaskIds = extractReferencedTaskIds(input.commit.message);
  let linkedTaskCount = 0;
  let unresolvedTaskIds: string[] = [];
  let linkedTaskSummaries: Array<{ id: string; title: string }> = [];
  const taskStatusResults: TaskStatusUpdateResult[] = [];

  if (referencedTaskIds.length > 0) {
    const taskRecords = referencedTaskIds.map((taskId) => new RecordId("task", taskId));
    const [taskRows] = await input.surreal
      .query<[Array<{ id: RecordId<"task", string>; title: string; status: string }> ]>(
        "SELECT id, title, status FROM task WHERE workspace = $workspace AND id IN $taskIds;",
        { workspace: input.workspaceRecord, taskIds: taskRecords },
      )
      .collect<[Array<{ id: RecordId<"task", string>; title: string; status: string }>]>();

    const foundTaskIds = new Set(taskRows.map((row) => row.id.id as string));
    unresolvedTaskIds = referencedTaskIds.filter((id) => !foundTaskIds.has(id));

    for (const task of taskRows) {
      await input.surreal
        .relate(task.id, new RecordId("implemented_by", randomUUID()), commitRecord, {
          commit_sha: input.commit.sha,
          linked_at: input.now,
        })
        .output("after");
    }

    linkedTaskCount = taskRows.length;
    linkedTaskSummaries = taskRows.map((row) => ({
      id: row.id.id as string,
      title: row.title,
    }));

    // Determine and apply task status updates based on branch
    const statusUpdates = determineTaskStatusUpdates({
      tasks: taskRows.map((row) => ({
        taskId: row.id.id as string,
        currentStatus: row.status,
      })),
      isDefaultBranch: input.isDefaultBranch,
    });

    for (const update of statusUpdates) {
      try {
        await updateTaskStatus({
          surreal: input.surreal,
          workspaceRecord: input.workspaceRecord,
          taskRecord: new RecordId("task", update.taskId),
          status: update.targetStatus,
        });
        taskStatusResults.push({ taskId: update.taskId, status: update.targetStatus });
        log.info("webhook.commit.task_status", "Updated task status from push", {
          taskId: update.taskId,
          status: update.targetStatus,
          sha: input.commit.sha,
          isDefaultBranch: input.isDefaultBranch,
        });
      } catch (error) {
        log.error("webhook.commit.task_status_failed", "Failed to update task status", error, {
          taskId: update.taskId,
          sha: input.commit.sha,
        });
      }
    }
  }

  log.info("webhook.commit.task_refs", "Processed explicit commit task references", {
    sha: input.commit.sha,
    referencedTaskCount: referencedTaskIds.length,
    linkedTaskCount,
    unresolvedTaskCount: unresolvedTaskIds.length,
  });

  const extractionSourceText = buildCommitExtractionSourceText(
    input.commit.message,
    linkedTaskSummaries,
    unresolvedTaskIds,
  );

  // Load workspace graph context for extraction
  const graphContext = await loadWorkspaceGraphContext(
    input.surreal,
    input.workspaceRecord,
    60,
  );

  // Run extraction on commit message
  const extractionOutput = await extractStructuredGraph({
    extractionModel: input.extractionModel,
    conversationHistory: [],
    graphContext,
    sourceText: extractionSourceText,
    onboarding: false,
    workspaceName: input.workspaceName,
    projectNames: input.projectNames,
  });

  // Persist extracted entities and relationships
  const persisted = await persistExtractionOutput({
    surreal: input.surreal,
    extractionModel: input.extractionModel,
    embeddingModel: input.embeddingModel,
    embeddingDimension: input.embeddingDimension,
    extractionModelId: input.extractionModelId,
    extractionStoreThreshold: input.extractionStoreThreshold,
    workspaceRecord: input.workspaceRecord,
    sourceRecord: commitRecord as SourceRecord,
    sourceKind: "git_commit",
    sourceLabel: `commit ${input.commit.sha.slice(0, 8)}`,
    promptText: extractionSourceText,
    output: extractionOutput,
    sourceCommitRecord: commitRecord,
    now: input.now,
  });

  // Auto-link decisions based on confidence
  const autoLinkedDecisions: string[] = [];
  const observationsCreated: string[] = [];
  const actions = classifyDecisionLinks(persisted.entities, input.autoLinkThreshold);

  for (const action of actions) {
    const decisionRecord = new RecordId("decision", action.entityId);

    if (action.action === "auto_link") {
      await input.surreal
        .relate(decisionRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
          commit_sha: input.commit.sha,
          linked_at: input.now,
        })
        .output("after");

      autoLinkedDecisions.push(action.entityId);
      log.info("webhook.commit.autolinked", "Auto-linked decision to commit", {
        decisionId: action.entityId,
        sha: input.commit.sha,
        confidence: action.confidence,
      });
    } else {
      const observation = await createObservation({
        surreal: input.surreal,
        workspaceRecord: input.workspaceRecord,
        text: `Commit ${input.commit.sha.slice(0, 8)} may implement decision "${action.text}" (confidence: ${(action.confidence * 100).toFixed(0)}%). Please confirm.`,
        severity: "info",
        sourceAgent: "git_webhook",
        now: input.now,
        relatedRecords: [decisionRecord],
      });

      observationsCreated.push(observation.id as string);
      log.info("webhook.commit.observation", "Created confirmation observation", {
        decisionId: action.entityId,
        sha: input.commit.sha,
        confidence: action.confidence,
      });
    }
  }

  return {
    commitRecord,
    entities: persisted.entities,
    relationships: persisted.relationships,
    autoLinkedDecisions,
    observationsCreated,
    taskStatusUpdates: taskStatusResults,
  };
}

function buildCommitExtractionSourceText(
  message: string,
  linkedTasks: Array<{ id: string; title: string }>,
  unresolvedTaskIds: string[],
): string {
  if (linkedTasks.length === 0 && unresolvedTaskIds.length === 0) {
    return message;
  }

  const lines = [message, "", "Explicit task references parsed from commit message:"];
  for (const task of linkedTasks) {
    lines.push(`- task:${task.id} (workspace task title: ${task.title})`);
  }
  for (const taskId of unresolvedTaskIds) {
    lines.push(`- task:${taskId} (not found in this workspace)`);
  }
  return lines.join("\n");
}

/**
 * Learning Diagnosis: Observation Clustering, Root Cause Classification, and Learning Proposals
 *
 * Groups open observations by embedding similarity into clusters,
 * checks if active learnings already cover each cluster pattern,
 * classifies root causes via LLM structured output, and proposes learnings.
 *
 * Pure query functions + pipeline composition. IO at boundaries only.
 *
 * Step 01-01: Clustering + coverage check
 * Step 01-02: Root cause classification with LLM structured output
 * Step 01-03: Learning proposer + graph scan integration
 */

import { RecordId, type Surreal } from "surrealdb";
import { generateObject, type LanguageModel } from "ai";
import { rootCauseSchema, type RootCauseClassification } from "./schemas";
import { OBSERVER_IDENTITY } from "../agents/observer/prompt";
import { createTelemetryConfig, recordLlmMetrics, recordLlmError } from "../telemetry/ai-telemetry";
import { FUNCTION_IDS } from "../telemetry/function-ids";
import { checkRateLimit, suggestLearning } from "../learning/detector";
import { createObservation, type EmbeddingDeps } from "../observation/queries";
import { cosineSimilarity, createEmbeddingVector } from "../graph/embeddings";
import { analyzeTrend, type ScorePoint, type TrendPattern, type TrendResult } from "../behavior/trends";
import type { CreateLearningInput } from "../learning/types";
import type { embed } from "ai";
import { log } from "../telemetry/logger";

type EmbeddingModel = Parameters<typeof embed>[0]["model"];

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type ObservationWithEmbedding = {
  id: string;
  text: string;
  severity: string;
  embedding: number[];
  entityRefs: string[];
};

export type ObservationCluster = {
  observations: Array<{ id: string; text: string; severity: string; entityRefs: string[] }>;
  representativeText: string;
  clusterSize: number;
};

export type CoverageCheckResult =
  | { covered: false }
  | { covered: true; matchedLearningText: string; similarity: number };

export type DiagnosticResult = {
  learning_proposals_created: number;
  coverage_skips: number;
  clusters_found: number;
};

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------

const CLUSTER_SIMILARITY_THRESHOLD = 0.75;
const MINIMUM_CLUSTER_SIZE = 3;
const TIME_WINDOW_DAYS = 14;
// Coverage threshold is lower than typical dedup thresholds (0.85) because
// we compare observation-text centroids (descriptive, noisy) against learning-text
// embeddings (directive, concise). Cross-form comparisons consistently score
// 30-40% lower on cosine similarity than same-form comparisons.
const COVERAGE_SIMILARITY_THRESHOLD = 0.50;
// Same cross-domain text form issue as coverage threshold — observation
// centroids vs dismissed learning embeddings. Lower than the dismissed
// re-suggestion gate (0.85) in suggestLearning() which compares same-form texts.
const DISMISSED_PATTERN_SIMILARITY_THRESHOLD = 0.50;

// ---------------------------------------------------------------------------
// Observation query (IO boundary)
// ---------------------------------------------------------------------------

/**
 * Queries open/acknowledged observations from the past 14 days with embeddings.
 * Uses two-step KNN pattern per SurrealDB HNSW+WHERE bug.
 */
export async function queryRecentObservationsWithEmbeddings(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
): Promise<ObservationWithEmbedding[]> {
  const cutoff = new Date(Date.now() - TIME_WINDOW_DAYS * 24 * 60 * 60 * 1000);

  const [rows] = await surreal.query<[Array<{
    id: RecordId<"observation">;
    text: string;
    severity: string;
    embedding: number[];
    entity_refs: Array<RecordId | string>;
    created_at: string;
  }>]>(
    `SELECT id, text, severity, embedding, created_at,
            ->observes->task.id AS entity_refs
     FROM observation
     WHERE workspace = $ws
       AND status IN ["open", "acknowledged"]
       AND created_at > $cutoff
       AND embedding IS NOT NONE
     ORDER BY created_at DESC
     LIMIT 200;`,
    { ws: workspaceRecord, cutoff },
  );

  return (rows ?? []).map((row) => ({
    id: row.id.id as string,
    text: row.text,
    severity: row.severity,
    embedding: row.embedding,
    entityRefs: (row.entity_refs ?? [])
      .filter((ref): ref is RecordId => typeof ref === "object" && ref !== null && "id" in ref)
      .map((ref) => `task:${ref.id as string}`),
  }));
}

// ---------------------------------------------------------------------------
// Pure clustering (no IO)
// ---------------------------------------------------------------------------

/**
 * Clusters observations by pairwise embedding similarity using single-linkage.
 *
 * Algorithm:
 * 1. Build adjacency: observation A is neighbor of B if similarity > threshold
 * 2. Connected components via BFS form clusters
 * 3. Filter clusters by minimum size
 *
 * Pure function -- no IO.
 */
export function clusterObservationsBySimilarity(
  observations: ObservationWithEmbedding[],
  similarityThreshold: number = CLUSTER_SIMILARITY_THRESHOLD,
  minimumClusterSize: number = MINIMUM_CLUSTER_SIZE,
): ObservationCluster[] {
  if (observations.length < minimumClusterSize) return [];

  // Build adjacency list
  const adjacency = new Map<number, Set<number>>();
  for (let i = 0; i < observations.length; i++) {
    adjacency.set(i, new Set());
  }

  for (let i = 0; i < observations.length; i++) {
    for (let j = i + 1; j < observations.length; j++) {
      const similarity = cosineSimilarity(
        observations[i].embedding,
        observations[j].embedding,
      );
      if (similarity > similarityThreshold) {
        adjacency.get(i)!.add(j);
        adjacency.get(j)!.add(i);
      }
    }
  }

  // BFS to find connected components
  const visited = new Set<number>();
  const clusters: ObservationCluster[] = [];

  for (let i = 0; i < observations.length; i++) {
    if (visited.has(i)) continue;

    const component: number[] = [];
    const queue = [i];
    visited.add(i);

    while (queue.length > 0) {
      const current = queue.shift()!;
      component.push(current);

      for (const neighbor of adjacency.get(current)!) {
        if (!visited.has(neighbor)) {
          visited.add(neighbor);
          queue.push(neighbor);
        }
      }
    }

    if (component.length >= minimumClusterSize) {
      const clusterObservations = component.map((idx) => ({
        id: observations[idx].id,
        text: observations[idx].text,
        severity: observations[idx].severity,
        entityRefs: observations[idx].entityRefs,
      }));

      // Representative text: the observation with highest average similarity to others in cluster
      const representativeIndex = pickRepresentativeIndex(component, observations);

      clusters.push({
        observations: clusterObservations,
        representativeText: observations[representativeIndex].text,
        clusterSize: component.length,
      });
    }
  }

  return clusters;
}

/**
 * Computes the centroid (element-wise average) of a set of embedding vectors.
 * This reduces noise from individual observation text variations, producing
 * a more representative embedding for cluster-level similarity comparisons.
 */
function computeCentroidEmbedding(embeddings: number[][]): number[] {
  if (embeddings.length === 0) return [];
  if (embeddings.length === 1) return embeddings[0];

  const dimension = embeddings[0].length;
  const centroid = new Array<number>(dimension).fill(0);

  for (const embedding of embeddings) {
    for (let i = 0; i < dimension; i++) {
      centroid[i] += embedding[i];
    }
  }

  for (let i = 0; i < dimension; i++) {
    centroid[i] /= embeddings.length;
  }

  return centroid;
}

/**
 * Picks the observation with highest average similarity to other cluster members.
 */
function pickRepresentativeIndex(
  componentIndices: number[],
  observations: ObservationWithEmbedding[],
): number {
  let bestIndex = componentIndices[0];
  let bestAvgSimilarity = -1;

  for (const i of componentIndices) {
    let totalSimilarity = 0;
    for (const j of componentIndices) {
      if (i !== j) {
        totalSimilarity += cosineSimilarity(
          observations[i].embedding,
          observations[j].embedding,
        );
      }
    }
    const avgSimilarity = totalSimilarity / (componentIndices.length - 1);
    if (avgSimilarity > bestAvgSimilarity) {
      bestAvgSimilarity = avgSimilarity;
      bestIndex = i;
    }
  }

  return bestIndex;
}

// ---------------------------------------------------------------------------
// Coverage check (IO boundary -- KNN query)
// ---------------------------------------------------------------------------

/**
 * Checks if any learning with a given status covers the cluster pattern.
 * Uses two-step KNN pattern per SurrealDB HNSW+WHERE bug, with brute-force fallback.
 */
async function checkLearningCoverage(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
  clusterEmbedding: number[],
  learningStatus: "active" | "dismissed",
  similarityThreshold: number,
): Promise<CoverageCheckResult> {
  const results = await surreal
    .query<[undefined, Array<{ text: string; similarity: number }>]>(
      [
        "LET $candidates = SELECT id, text, workspace, status,",
        "vector::similarity::cosine(embedding, $embedding) AS similarity",
        "FROM learning WHERE embedding <|10, COSINE|> $embedding;",
        "SELECT text, similarity FROM $candidates",
        "WHERE workspace = $ws AND status = $status AND similarity > $threshold",
        "ORDER BY similarity DESC LIMIT 1;",
      ].join("\n"),
      {
        embedding: clusterEmbedding,
        ws: workspaceRecord,
        status: learningStatus,
        threshold: similarityThreshold,
      },
    );

  const matches = results[1] ?? [];
  const match = matches[0];
  if (match) {
    return { covered: true, matchedLearningText: match.text, similarity: match.similarity };
  }

  // Brute-force fallback when HNSW index hasn't indexed recent inserts
  const [learnings] = await surreal.query<[Array<{ text: string; embedding: number[] }>]>(
    `SELECT text, embedding FROM learning
     WHERE workspace = $ws
       AND status = $status
       AND embedding IS NOT NONE;`,
    { ws: workspaceRecord, status: learningStatus },
  );

  if (learningStatus === "active") {
    log.info("observer.learning.coverage_fallback", "Fallback coverage check", {
      activeLearningsCount: (learnings ?? []).length,
      workspaceId: workspaceRecord.id,
    });
  }

  for (const learning of learnings ?? []) {
    const similarity = cosineSimilarity(clusterEmbedding, learning.embedding);
    if (similarity > similarityThreshold) {
      return { covered: true, matchedLearningText: learning.text, similarity };
    }
  }

  return { covered: false };
}

export async function checkCoverageAgainstActiveLearnings(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
  clusterEmbedding: number[],
): Promise<CoverageCheckResult> {
  return checkLearningCoverage(surreal, workspaceRecord, clusterEmbedding, "active", COVERAGE_SIMILARITY_THRESHOLD);
}

export async function checkDismissedLearningForCluster(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
  clusterEmbedding: number[],
): Promise<CoverageCheckResult> {
  return checkLearningCoverage(surreal, workspaceRecord, clusterEmbedding, "dismissed", DISMISSED_PATTERN_SIMILARITY_THRESHOLD);
}

// ---------------------------------------------------------------------------
// Root cause classification (LLM structured output)
// ---------------------------------------------------------------------------

const CONFIDENCE_THRESHOLD = 0.70;
const CLASSIFICATION_TIMEOUT_MS = 30_000;

/**
 * Builds the LLM prompt for root cause classification.
 * Pure function -- formats cluster and context into prompt text.
 */
function buildClassificationPrompt(
  cluster: ObservationCluster,
  existingLearnings: string[],
): string {
  const observationQuotes = cluster.observations
    .map((obs, i) => `  ${i + 1}. [${obs.severity}] "${obs.text}"`)
    .join("\n");

  const entityRefsList = [
    ...new Set(cluster.observations.flatMap((obs) => obs.entityRefs)),
  ];
  const entityRefsText = entityRefsList.length > 0
    ? entityRefsList.map((ref) => `  - ${ref}`).join("\n")
    : "  No linked entities.";

  const learningsText = existingLearnings.length > 0
    ? existingLearnings.map((l, i) => `  ${i + 1}. ${l}`).join("\n")
    : "  No active learnings.";

  return `You are performing root cause analysis on a recurring pattern detected in the workspace.

## Pattern Detected
Representative text: "${cluster.representativeText}"

Observation quotes (${cluster.clusterSize} occurrences):
${observationQuotes}

## Related Entities
${entityRefsText}

## Existing Active Learnings
${learningsText}

## Classification Instructions
Determine WHY this pattern keeps recurring:

1. Policy Failure: The governance rules allowed something they shouldn't.
   -> Propose a constraint that tightens the boundary.

2. Context Failure: The agent lacked information it needed to act correctly.
   -> Propose an instruction that injects the missing context.

3. Behavioral Drift: The agent had the information but didn't apply it.
   -> Propose a constraint that reinforces the expected behavior.

Set should_propose_learning to true ONLY if:
- confidence >= 0.70
- You have high conviction in both the category AND the proposed text
- The proposed learning is specific enough to be actionable

Set should_propose_learning to false if:
- The root cause is ambiguous or could fit multiple categories
- The proposed learning text is too generic ("be more careful")
- The evidence is insufficient to justify a permanent behavioral rule

For proposed_learning_type, choose based on the fix needed:
- "constraint" for must-follow rules (policy fixes, behavioral reinforcement)
- "instruction" for conditional guidance (context injection, situational awareness)

In evidence_refs, list the observation IDs in table:id format (e.g. observation:uuid).
In target_agents, list the agent types that should receive this learning.`;
}

/**
 * Classifies the root cause of an observation cluster using LLM structured output.
 * Returns undefined on any failure (timeout, rate limit, invalid output).
 */
export async function classifyRootCause(
  model: LanguageModel,
  cluster: ObservationCluster,
  existingLearnings: string[],
): Promise<RootCauseClassification | undefined> {
  const start = Date.now();

  try {
    const prompt = buildClassificationPrompt(cluster, existingLearnings);

    const result = await generateObject({
      model,
      system: OBSERVER_IDENTITY,
      schema: rootCauseSchema,
      experimental_telemetry: createTelemetryConfig(FUNCTION_IDS.OBSERVER_LEARNING_DIAGNOSIS),
      prompt,
      abortSignal: AbortSignal.timeout(CLASSIFICATION_TIMEOUT_MS),
    });

    const latencyMs = Date.now() - start;
    recordLlmMetrics(FUNCTION_IDS.OBSERVER_LEARNING_DIAGNOSIS, result.usage, latencyMs);
    log.info("observer.llm.root_cause", "Root cause classification completed", {
      latencyMs,
      category: result.object.category,
      confidence: result.object.confidence,
      shouldPropose: result.object.should_propose_learning,
    });

    return result.object;
  } catch (error) {
    const latencyMs = Date.now() - start;
    recordLlmError(FUNCTION_IDS.OBSERVER_LEARNING_DIAGNOSIS, error instanceof Error ? error.constructor.name : "unknown");
    log.error("observer.llm.root_cause_error", "Root cause classification failed", {
      error,
      latencyMs,
    });
    return undefined;
  }
}

// ---------------------------------------------------------------------------
// Dual gate: decide whether to propose learning or create observation
// ---------------------------------------------------------------------------

/**
 * Applies the dual gate: should_propose_learning AND confidence >= threshold.
 */
function shouldProposeLearning(classification: RootCauseClassification): boolean {
  return classification.should_propose_learning && classification.confidence >= CONFIDENCE_THRESHOLD;
}

/**
 * Maps a root cause classification to a CreateLearningInput.
 */
function rootCauseToLearningInput(
  classification: RootCauseClassification,
  cluster: ObservationCluster,
): CreateLearningInput {
  return {
    text: classification.proposed_learning_text,
    learningType: classification.proposed_learning_type,
    source: "agent",
    suggestedBy: "observer",
    patternConfidence: classification.confidence,
    targetAgents: classification.target_agents,
    evidenceIds: cluster.observations.map((obs) => ({
      table: "observation" as const,
      id: obs.id,
    })),
  };
}

// ---------------------------------------------------------------------------
// Query existing active learnings for classification context
// ---------------------------------------------------------------------------

async function queryActiveLearningTexts(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
): Promise<string[]> {
  const [rows] = await surreal.query<[Array<{ text: string; created_at: string }>]>(
    `SELECT text, created_at FROM learning
     WHERE workspace = $ws AND status = "active"
     ORDER BY created_at DESC
     LIMIT 20;`,
    { ws: workspaceRecord },
  );
  return (rows ?? []).map((r) => r.text);
}

// ---------------------------------------------------------------------------
// Behavior Learning Bridge
// ---------------------------------------------------------------------------

export type BehaviorTrendEntry = {
  identityId: string;
  metricType: string;
  trend: TrendResult;
  behaviorIds: string[];
  scorePoints: ScorePoint[];
};

export type ProposeBehaviorLearningInput = {
  surreal: Surreal;
  workspaceRecord: RecordId<"workspace", string>;
  identityId: string;
  metricType: string;
  behaviorIds: string[];
  trendPattern: TrendPattern;
  now: Date;
};

export type ProposeBehaviorLearningResult =
  | { created: true; learningRecord: RecordId<"learning", string> }
  | { created: false; reason: "rate_limited"; count: number }
  | { created: false; reason: "dismissed_similarity"; matchedText: string };

/**
 * Queries all behavior records in a workspace, groups by identity + metric type,
 * and analyzes trends for each group.
 *
 * Returns only groups with enough data points for trend analysis.
 */
export async function queryWorkspaceBehaviorTrends(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
): Promise<BehaviorTrendEntry[]> {
  // Query all behavior records with their identity via exhibits edges
  const [rows] = await surreal.query<[Array<{
    id: RecordId<"behavior">;
    metric_type: string;
    score: number;
    created_at: string;
    identity_id: RecordId<"identity">[];
  }>]>(
    `SELECT id, metric_type, score, created_at,
            <-exhibits<-identity.id AS identity_id
     FROM behavior
     WHERE workspace = $ws
     ORDER BY created_at ASC;`,
    { ws: workspaceRecord },
  );

  if (!rows || rows.length === 0) return [];

  // Group by identity + metric_type
  const groups = new Map<string, {
    identityId: string;
    metricType: string;
    points: ScorePoint[];
    behaviorIds: string[];
  }>();

  for (const row of rows) {
    const identityIds = row.identity_id ?? [];
    if (identityIds.length === 0) continue;

    const identityId = identityIds[0].id as string;
    const key = `${identityId}::${row.metric_type}`;

    if (!groups.has(key)) {
      groups.set(key, {
        identityId,
        metricType: row.metric_type,
        points: [],
        behaviorIds: [],
      });
    }

    const group = groups.get(key)!;
    group.points.push({ score: row.score, timestamp: row.created_at });
    group.behaviorIds.push(row.id.id as string);
  }

  // Analyze trend for each group
  const entries: BehaviorTrendEntry[] = [];
  for (const group of groups.values()) {
    const trend = analyzeTrend(group.points);
    entries.push({
      identityId: group.identityId,
      metricType: group.metricType,
      trend,
      behaviorIds: group.behaviorIds,
      scorePoints: group.points,
    });
  }

  return entries;
}

/**
 * Rate limit guard for behavior-sourced learning proposals.
 * Returns early if >= 5 observer proposals exist in the past 7 days.
 */
export async function checkBehaviorLearningRateLimit(input: {
  surreal: Surreal;
  workspaceRecord: RecordId<"workspace", string>;
}): Promise<{ blocked: boolean; count: number }> {
  return checkRateLimit({
    surreal: input.surreal,
    workspaceRecord: input.workspaceRecord,
    agentType: "observer",
  });
}

/**
 * Composes a learning proposal from behavior trend data and submits it
 * via the existing suggestLearning pipeline (with rate limit + collision detection).
 *
 * Behavior records are linked as learning_evidence via the extended relation OUT.
 */
export async function proposeBehaviorLearning(
  input: ProposeBehaviorLearningInput,
): Promise<ProposeBehaviorLearningResult> {
  const learningText = buildBehaviorLearningText(
    input.identityId,
    input.metricType,
    input.trendPattern,
  );

  const learningInput: CreateLearningInput = {
    text: learningText,
    learningType: "constraint",
    source: "agent",
    suggestedBy: "observer",
    patternConfidence: 0.80,
    targetAgents: [input.identityId],
    evidenceIds: input.behaviorIds.map((id) => ({
      table: "behavior" as const,
      id,
    })),
  };

  const result = await suggestLearning({
    surreal: input.surreal,
    workspaceRecord: input.workspaceRecord,
    learning: learningInput,
    now: input.now,
  });

  if (result.created) {
    log.info("observer.behavior.learning_proposed", "Learning proposed from behavior trend", {
      identityId: input.identityId,
      metricType: input.metricType,
      trendPattern: input.trendPattern,
      learningId: result.learningRecord.id,
    });
    return { created: true, learningRecord: result.learningRecord };
  }

  log.info("observer.behavior.learning_blocked", "Behavior learning proposal blocked", {
    identityId: input.identityId,
    metricType: input.metricType,
    reason: result.reason,
  });

  return result;
}

/**
 * Builds a descriptive learning text from behavior trend data.
 * Pure function -- no IO.
 */
function buildBehaviorLearningText(
  identityId: string,
  metricType: string,
  trendPattern: TrendPattern,
): string {
  const metricLabel = metricType.replace(/_/g, " ");

  switch (trendPattern) {
    case "drift":
      return `Agent ${identityId} shows sustained decline in ${metricLabel}. ` +
        `Enforce ${metricLabel} standards before proceeding with other work.`;
    case "flat":
      return `Agent ${identityId} shows persistent stagnation in ${metricLabel} below threshold. ` +
        `Current learning interventions for ${metricLabel} are ineffective -- consider revising approach.`;
    default:
      return `Agent ${identityId} shows concerning ${trendPattern} pattern in ${metricLabel}. ` +
        `Review ${metricLabel} compliance and reinforce expected behavior.`;
  }
}

// ---------------------------------------------------------------------------
// Process a single uncovered cluster: classify and propose or observe
// ---------------------------------------------------------------------------

async function processUncoveredCluster(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
  model: LanguageModel,
  cluster: ObservationCluster,
  existingLearnings: string[],
  embeddingModel?: EmbeddingModel,
  embeddingDimension?: number,
): Promise<{ proposed: boolean }> {
  const classification = await classifyRootCause(model, cluster, existingLearnings);

  if (!classification) {
    log.info("observer.learning.classification_skipped", "Skipping cluster due to failed LLM classification", {
      clusterSize: cluster.clusterSize,
      representativeText: cluster.representativeText.slice(0, 100),
    });
    return { proposed: false };
  }

  if (shouldProposeLearning(classification)) {
    const learningInput = rootCauseToLearningInput(classification, cluster);

    // Generate embedding for the proposed learning text to enable
    // dismissed similarity gate and persist with the learning record
    const embedding = embeddingModel && embeddingDimension
      ? await createEmbeddingVector(embeddingModel, learningInput.text, embeddingDimension)
      : undefined;

    const result = await suggestLearning({
      surreal,
      workspaceRecord,
      learning: learningInput,
      embedding,
      now: new Date(),
    });

    if (result.created) {
      log.info("observer.learning.proposed", "Learning proposed from root cause analysis", {
        category: classification.category,
        confidence: classification.confidence,
        learningType: classification.proposed_learning_type,
        learningId: result.learningRecord.id,
      });
      return { proposed: true };
    }

    log.info("observer.learning.gate_blocked", "Learning proposal blocked by safety gate", {
      reason: result.reason,
    });
    return { proposed: false };
  }

  // Dual gate failed: create an observation instead
  await createObservation({
    surreal,
    workspaceRecord,
    text: `Emerging pattern detected but root cause unclear (${classification.category}, confidence: ${classification.confidence.toFixed(2)}): ${classification.reasoning}`,
    severity: "info",
    sourceAgent: "observer_agent",
    observationType: "pattern",
    now: new Date(),
    embeddingDeps: embeddingModel && embeddingDimension
      ? { embeddingModel, embeddingDimension }
      : undefined,
  });

  log.info("observer.learning.low_confidence", "Pattern observed but confidence too low for learning proposal", {
    category: classification.category,
    confidence: classification.confidence,
    shouldPropose: classification.should_propose_learning,
  });

  return { proposed: false };
}

// ---------------------------------------------------------------------------
// Diagnostic pipeline orchestrator
// ---------------------------------------------------------------------------

/**
 * Runs the observation clustering, coverage check, and root cause classification pipeline.
 *
 * Pipeline:
 * 1. Query recent observations with embeddings
 * 2. Cluster by pairwise similarity
 * 3. For each cluster, check coverage against active learnings
 * 4. For uncovered clusters, classify root cause via LLM
 * 5. Propose learning or create observation based on dual gate
 */
export async function runDiagnosticClustering(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
  observerModel: LanguageModel,
  embeddingModel: EmbeddingModel,
  embeddingDimension: number,
): Promise<{
  clusters: ObservationCluster[];
  uncoveredClusters: ObservationCluster[];
  result: DiagnosticResult;
}> {
  const diagnosticResult: DiagnosticResult = {
    learning_proposals_created: 0,
    coverage_skips: 0,
    clusters_found: 0,
  };

  // Step 1: Query recent observations
  const observations = await queryRecentObservationsWithEmbeddings(
    surreal,
    workspaceRecord,
  );

  if (observations.length < MINIMUM_CLUSTER_SIZE) {
    return { clusters: [], uncoveredClusters: [], result: diagnosticResult };
  }

  // Step 2: Cluster by similarity (pure)
  const clusters = clusterObservationsBySimilarity(observations);
  diagnosticResult.clusters_found = clusters.length;

  if (clusters.length === 0) {
    return { clusters: [], uncoveredClusters: [], result: diagnosticResult };
  }

  // Step 3: Coverage check for each cluster
  const uncoveredClusters: ObservationCluster[] = [];

  for (const cluster of clusters) {
    // Compute cluster centroid embedding (average of all observation embeddings)
    // to reduce noise from individual observation text variations
    const clusterObsWithEmbeddings = cluster.observations
      .map((co) => observations.find((o) => o.id === co.id))
      .filter((o): o is ObservationWithEmbedding => o !== undefined && o.embedding.length > 0);

    if (clusterObsWithEmbeddings.length === 0) {
      uncoveredClusters.push(cluster);
      continue;
    }

    const centroidEmbedding = computeCentroidEmbedding(
      clusterObsWithEmbeddings.map((o) => o.embedding),
    );

    const coverage = await checkCoverageAgainstActiveLearnings(
      surreal,
      workspaceRecord,
      centroidEmbedding,
    );

    if (coverage.covered) {
      log.info("observer.learning.coverage_skip", "Cluster pattern already covered by active learning", {
        clusterSize: cluster.clusterSize,
        matchedLearningText: coverage.matchedLearningText,
        similarity: coverage.similarity,
      });
      diagnosticResult.coverage_skips += 1;
      continue;
    }

    // Check if a dismissed learning already covers this pattern
    const dismissedCheck = await checkDismissedLearningForCluster(
      surreal,
      workspaceRecord,
      centroidEmbedding,
    );

    if (dismissedCheck.covered) {
      log.info("observer.learning.dismissed_skip", "Cluster pattern matches a previously dismissed learning", {
        clusterSize: cluster.clusterSize,
        matchedLearningText: dismissedCheck.matchedLearningText,
        similarity: dismissedCheck.similarity,
      });
      diagnosticResult.coverage_skips += 1;
    } else {
      uncoveredClusters.push(cluster);
    }
  }

  // Step 4: Root cause classification for uncovered clusters
  if (uncoveredClusters.length > 0) {
    const existingLearnings = await queryActiveLearningTexts(surreal, workspaceRecord);

    for (const cluster of uncoveredClusters) {
      const { proposed } = await processUncoveredCluster(
        surreal,
        workspaceRecord,
        observerModel,
        cluster,
        existingLearnings,
        embeddingModel,
        embeddingDimension,
      );

      if (proposed) {
        diagnosticResult.learning_proposals_created += 1;
      }
    }
  }

  return { clusters, uncoveredClusters, result: diagnosticResult };
}

/**
 * Trace Response Analyzer — Observer intelligence for per-trace analysis.
 *
 * Pure analysis pipeline that examines LLM call traces for:
 * 1. Contradictions with confirmed workspace decisions (Tier 1 KNN + Tier 2 LLM)
 * 2. Unrecorded decisions (decision-shaped statements with no matching record)
 *
 * Pipeline: extract text -> check stop_reason -> embed response
 *   -> KNN against confirmed decisions -> Tier 2 LLM verification
 *   -> create observations
 *
 * Dependencies injected as function parameters (hexagonal ports).
 * All domain logic is pure; IO happens at the boundary via injected adapters.
 */

import { RecordId, type Surreal } from "surrealdb";
import type { LanguageModel } from "ai";
import type { embed } from "ai";
import { z } from "zod";
import { createObservation, type ObserveTargetRecord, type EmbeddingDeps } from "../observation/queries";
import { createEmbeddingVector } from "../graph/embeddings";
import { log } from "../telemetry/logger";

type EmbeddingModel = Parameters<typeof embed>[0]["model"];

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type TraceAnalysisInput = {
  surreal: Surreal;
  workspaceRecord: RecordId<"workspace", string>;
  traceId: string;
  traceBody?: Record<string, unknown>;
  observerModel: LanguageModel;
  embeddingModel: EmbeddingModel;
  embeddingDimension: number;
};

export type TraceAnalysisResult = {
  observations_created: number;
  skipped: boolean;
  reason?: string;
};

type DecisionCandidate = {
  id: RecordId<"decision", string>;
  summary: string;
  rationale?: string;
  score: number;
};

type ContradictionVerdict = {
  isContradiction: boolean;
  confidence: number;
  reasoning: string;
};

// ---------------------------------------------------------------------------
// Response text extraction (pure)
// ---------------------------------------------------------------------------

/**
 * Extracts readable text from the trace output FLEXIBLE field.
 * Handles Anthropic-style content blocks: text blocks and tool inputs.
 */
export function extractResponseText(output?: Record<string, unknown>): string {
  if (!output) return "";

  const parts: string[] = [];

  // Extract from content array (Anthropic Messages API format)
  const content = output.content;
  if (Array.isArray(content)) {
    for (const block of content) {
      if (typeof block === "object" && block !== null) {
        const typedBlock = block as Record<string, unknown>;
        if (typedBlock.type === "text" && typeof typedBlock.text === "string") {
          parts.push(typedBlock.text);
        }
        if (typedBlock.type === "tool_use" && typeof typedBlock.input === "object" && typedBlock.input !== null) {
          // Include tool inputs as they may contain decision-shaped content
          parts.push(JSON.stringify(typedBlock.input));
        }
      }
    }
  }

  return parts.join("\n\n");
}

/**
 * Checks whether a trace should be analyzed based on stop_reason.
 * Tool-use stop reasons indicate intermediate loop steps -- skip them.
 */
export function shouldAnalyzeTrace(
  stopReason?: string,
  traceBody?: Record<string, unknown>,
): boolean {
  // Check stop_reason from trace body top-level field
  const reason = stopReason
    ?? (traceBody?.stop_reason as string | undefined)
    ?? (traceBody?.output as Record<string, unknown> | undefined)?.stop_reason as string | undefined;

  if (reason === "tool_use") {
    return false;
  }

  return true;
}

// ---------------------------------------------------------------------------
// KNN decision search (two-step SurrealDB v3.0 workaround)
// ---------------------------------------------------------------------------

/**
 * Finds confirmed decisions similar to the given embedding using two-step
 * KNN query pattern (SurrealDB v3.0 workaround for KNN + WHERE bug).
 *
 * Step 1: KNN on HNSW index (no WHERE filter)
 * Step 2: Filter by workspace + confirmed status (B-tree index)
 */
async function findSimilarDecisions(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
  responseEmbedding: number[],
  threshold: number,
): Promise<DecisionCandidate[]> {
  const results = await surreal.query(
    `LET $candidates = SELECT id, summary, rationale, workspace, status,
        vector::similarity::cosine(embedding, $vec) AS score
      FROM decision WHERE embedding <|20, COSINE|> $vec;
     SELECT id, summary, rationale, score FROM $candidates
      WHERE workspace = $ws AND status = 'confirmed'
        AND score >= $threshold
      ORDER BY score DESC
      LIMIT 10;`,
    { vec: responseEmbedding, ws: workspaceRecord, threshold },
  );

  // Two-statement query: results[1] is the filtered result
  const rows = (results[1] ?? []) as Array<{
    id: RecordId<"decision", string>;
    summary: string;
    rationale?: string;
    score: number;
  }>;

  return rows;
}

// ---------------------------------------------------------------------------
// Tier 2 LLM verification
// ---------------------------------------------------------------------------

/**
 * Verifies whether a trace response actually contradicts a specific decision.
 * Returns structured verdict with confidence score.
 */
async function verifyContradiction(
  model: LanguageModel,
  responseText: string,
  decision: DecisionCandidate,
): Promise<ContradictionVerdict> {
  const { generateObject } = await import("ai");
  const { createTelemetryConfig } = await import("../telemetry/ai-telemetry");
  const { FUNCTION_IDS } = await import("../telemetry/function-ids");

  const contradictionSchema = z.object({
    is_contradiction: z.boolean().describe("Whether the response contradicts the decision"),
    confidence: z.number().describe("Confidence score 0.0-1.0"),
    reasoning: z.string().describe("Brief explanation"),
  });

  const { object } = await generateObject({
    model,
    schema: contradictionSchema,
    experimental_telemetry: createTelemetryConfig(FUNCTION_IDS.OBSERVER_VERIFICATION),
    prompt: `You are an AI governance observer. Determine if this LLM response contradicts a confirmed workspace decision.

CONFIRMED DECISION:
Summary: ${decision.summary}
${decision.rationale ? `Rationale: ${decision.rationale}` : ""}

LLM RESPONSE EXCERPT:
${responseText.slice(0, 2000)}

Does the LLM response implement or recommend something that directly contradicts this decision? Consider:
- Is the response actively violating the decision (not just mentioning alternatives)?
- Is the contradiction about the same domain/scope as the decision?
- Could the response be about external/third-party systems (not covered by the decision)?

Respond with is_contradiction (true/false), confidence (0.0-1.0), and brief reasoning.`,
  });

  return {
    isContradiction: object.is_contradiction,
    confidence: object.confidence,
    reasoning: object.reasoning,
  };
}

/**
 * Verifies whether a trace response contains an unrecorded decision.
 * Checks if the text makes architectural/strategic choices not in the graph.
 */
async function verifyMissingDecision(
  model: LanguageModel,
  responseText: string,
): Promise<{ isDecision: boolean; confidence: number; summary: string; reasoning: string }> {
  const { generateObject } = await import("ai");
  const { createTelemetryConfig } = await import("../telemetry/ai-telemetry");
  const { FUNCTION_IDS } = await import("../telemetry/function-ids");

  const missingDecisionSchema = z.object({
    is_decision: z.boolean().describe("Whether the response contains an unrecorded architectural/strategic decision"),
    confidence: z.number().describe("Confidence score 0.0-1.0"),
    summary: z.string().describe("Brief summary of the decision found, or empty string"),
    reasoning: z.string().describe("Brief explanation of why this is or is not an unrecorded decision"),
  });

  const { object } = await generateObject({
    model,
    schema: missingDecisionSchema,
    experimental_telemetry: createTelemetryConfig(FUNCTION_IDS.OBSERVER_VERIFICATION),
    prompt: `You are an AI governance observer. Determine if this LLM response contains an architectural or strategic decision that should be tracked.

LLM RESPONSE:
${responseText.slice(0, 2000)}

Decision signals to look for:
- "I've decided to use X instead of Y"
- "The right approach is X because..."
- Technology/framework/architecture choices with rationale
- Trade-off resolutions ("we should use X for this use case")

NOT decisions:
- Implementation details (variable names, code formatting)
- Following existing instructions/conventions
- Asking questions or presenting options without choosing

Does this response contain a decision-shaped statement? Respond with is_decision, confidence (0.0-1.0), a summary of the decision if found, and reasoning explaining your analysis.`,
  });

  return {
    isDecision: object.is_decision,
    confidence: object.confidence,
    summary: object.summary,
    reasoning: object.reasoning,
  };
}

// ---------------------------------------------------------------------------
// Contradiction detection pipeline
// ---------------------------------------------------------------------------

async function detectContradictions(
  input: TraceAnalysisInput,
  responseText: string,
  responseEmbedding: number[],
  config: { tier1Threshold: number; tier2ConfidenceMin: number },
): Promise<number> {
  const { surreal, workspaceRecord, traceId, observerModel } = input;
  const traceRecord = new RecordId("trace", traceId);

  // Tier 1: KNN search for similar confirmed decisions
  const candidates = await findSimilarDecisions(
    surreal,
    workspaceRecord,
    responseEmbedding,
    config.tier1Threshold,
  );

  if (candidates.length === 0) {
    log.info("observer.trace.no_candidates", "No similar decisions found for trace", { traceId });
    return 0;
  }

  log.info("observer.trace.candidates_found", "KNN candidates for contradiction check", {
    traceId,
    candidateCount: candidates.length,
  });

  // Tier 2: LLM verification on each candidate
  let observationsCreated = 0;

  for (const candidate of candidates) {
    try {
      const verdict = await verifyContradiction(observerModel, responseText, candidate);

      if (!verdict.isContradiction || verdict.confidence < config.tier2ConfidenceMin) {
        log.info("observer.trace.not_contradicted", "Candidate not contradicted or low confidence", {
          traceId,
          decisionId: candidate.id.id,
          isContradiction: verdict.isContradiction,
          confidence: verdict.confidence,
        });
        continue;
      }

      // Create contradiction observation
      const decisionRecord = new RecordId("decision", candidate.id.id as string) as ObserveTargetRecord;

      await createObservation({
        surreal,
        workspaceRecord,
        text: `Trace response contradicts confirmed decision "${candidate.summary}": ${verdict.reasoning}`,
        severity: "conflict",
        sourceAgent: "observer_agent",
        observationType: "contradiction",
        now: new Date(),
        relatedRecords: [traceRecord as ObserveTargetRecord, decisionRecord],
        confidence: verdict.confidence,
        verified: true,
        source: "llm",
        reasoning: verdict.reasoning,
        embeddingDeps: { embeddingModel, embeddingDimension },
      });

      observationsCreated += 1;

      log.info("observer.trace.contradiction_found", "Contradiction observation created", {
        traceId,
        decisionId: candidate.id.id,
        confidence: verdict.confidence,
      });
    } catch (error) {
      log.error("observer.trace.verification_error", "Tier 2 verification failed for candidate", {
        traceId,
        decisionId: candidate.id.id,
        error: error instanceof Error ? error.message : String(error),
      });
      // Continue with other candidates -- fail-skip per candidate
    }
  }

  return observationsCreated;
}

// ---------------------------------------------------------------------------
// Missing decision detection pipeline
// ---------------------------------------------------------------------------

async function detectMissingDecisions(
  input: TraceAnalysisInput,
  responseText: string,
  responseEmbedding: number[],
  config: { tier1Threshold: number; tier2ConfidenceMin: number },
): Promise<number> {
  const { surreal, workspaceRecord, traceId, observerModel } = input;
  const traceRecord = new RecordId("trace", traceId);

  // First check if the response contains decision signals via LLM
  try {
    const missingResult = await verifyMissingDecision(observerModel, responseText);

    if (!missingResult.isDecision || missingResult.confidence < config.tier2ConfidenceMin) {
      return 0;
    }

    // Check if a similar decision already exists (KNN search)
    const existingDecisions = await findSimilarDecisions(
      surreal,
      workspaceRecord,
      responseEmbedding,
      config.tier1Threshold,
    );

    // If we found a similar existing decision, it's not "missing"
    if (existingDecisions.length > 0) {
      log.info("observer.trace.decision_exists", "Decision-shaped content matches existing decision", {
        traceId,
        matchedDecisionId: existingDecisions[0].id.id,
      });
      return 0;
    }

    // No matching decision found -- create info observation
    await createObservation({
      surreal,
      workspaceRecord,
      text: `Unrecorded decision detected in trace: ${missingResult.summary}`,
      severity: "info",
      sourceAgent: "observer_agent",
      observationType: "validation",
      now: new Date(),
      relatedRecords: [traceRecord as ObserveTargetRecord],
      confidence: missingResult.confidence,
      verified: true,
      source: "llm",
      reasoning: missingResult.reasoning,
      embeddingDeps: { embeddingModel, embeddingDimension },
    });

    log.info("observer.trace.missing_decision", "Unrecorded decision observation created", {
      traceId,
      summary: missingResult.summary,
    });

    return 1;
  } catch (error) {
    log.error("observer.trace.missing_detection_error", "Missing decision detection failed", {
      traceId,
      error: error instanceof Error ? error.message : String(error),
    });
    return 0;
  }
}

// ---------------------------------------------------------------------------
// Configuration loader
// ---------------------------------------------------------------------------

async function loadIntelligenceConfig(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
): Promise<{
  enabled: boolean;
  tier1Threshold: number;
  tier2ConfidenceMin: number;
} | undefined> {
  const [rows] = await surreal.query<[Array<{
    contradiction_detection_enabled: boolean;
    contradiction_tier1_threshold: number;
    contradiction_tier2_confidence_min: number;
  }>]>(
    `SELECT contradiction_detection_enabled, contradiction_tier1_threshold, contradiction_tier2_confidence_min
     FROM proxy_intelligence_config
     WHERE workspace = $ws
     LIMIT 1;`,
    { ws: workspaceRecord },
  );

  const config = rows?.[0];
  if (!config) return undefined;

  return {
    enabled: config.contradiction_detection_enabled,
    tier1Threshold: config.contradiction_tier1_threshold,
    tier2ConfidenceMin: config.contradiction_tier2_confidence_min,
  };
}

// ---------------------------------------------------------------------------
// Main analysis entry point
// ---------------------------------------------------------------------------

/**
 * Analyzes an LLM call trace for contradictions and missing decisions.
 *
 * Pipeline:
 * 1. Check stop_reason -- skip tool_use (intermediate loop step)
 * 2. Extract text blocks from output FLEXIBLE field
 * 3. Contradiction detection: embed response -> KNN against decisions -> LLM verify
 * 4. Missing decision detection: extract signals -> embed -> KNN -> LLM verify
 *
 * Returns 200-safe result on all analysis errors (fail-skip pattern).
 */
export async function analyzeTraceResponse(
  input: TraceAnalysisInput,
): Promise<TraceAnalysisResult> {
  const { surreal, workspaceRecord, traceId, traceBody, embeddingModel, embeddingDimension } = input;

  // Step 1: Check stop_reason
  if (!shouldAnalyzeTrace(undefined, traceBody)) {
    log.info("observer.trace.skipped", "Trace skipped: tool_use stop_reason", { traceId });
    return { observations_created: 0, skipped: true, reason: "tool_use" };
  }

  // Step 2: Extract response text
  const output = traceBody?.output as Record<string, unknown> | undefined;
  const responseText = extractResponseText(output);

  if (responseText.trim().length === 0) {
    log.info("observer.trace.empty", "Trace skipped: no extractable text", { traceId });
    return { observations_created: 0, skipped: true, reason: "empty_response" };
  }

  // Load intelligence config
  const config = await loadIntelligenceConfig(surreal, workspaceRecord);
  if (!config || !config.enabled) {
    log.info("observer.trace.config_disabled", "Trace analysis skipped: not enabled", { traceId });
    return { observations_created: 0, skipped: true, reason: "not_enabled" };
  }

  // Step 3: Embed the response text
  const responseEmbedding = await createEmbeddingVector(
    embeddingModel,
    responseText.slice(0, 4000), // Limit embedding input
    embeddingDimension,
  );

  if (!responseEmbedding) {
    log.error("observer.trace.embedding_failed", "Failed to embed trace response", { traceId });
    return { observations_created: 0, skipped: true, reason: "embedding_failed" };
  }

  // Step 4: Run both detection pipelines
  const [contradictionCount, missingCount] = await Promise.all([
    detectContradictions(input, responseText, responseEmbedding, config),
    detectMissingDecisions(input, responseText, responseEmbedding, config),
  ]);

  const totalObservations = contradictionCount + missingCount;

  log.info("observer.trace.analysis_complete", "Trace analysis complete", {
    traceId,
    contradictions: contradictionCount,
    missingDecisions: missingCount,
    totalObservations,
  });

  return {
    observations_created: totalObservations,
    skipped: false,
  };
}

